SELECT * FROM operation_log
WHERE 1=1

    AND app_id = #{appId}


    AND user_name = #{userName}


    AND module = #{module}


    AND status = #{status}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}

ORDER BY create_time DESC
LIMIT #{rowIndex}, #{limit}

SELECT COUNT(*) FROM operation_log
WHERE 1=1

    AND app_id = #{appId}


    AND user_name = #{userName}


    AND module = #{module}


    AND status = #{status}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}
